const body = $input.first().json.body ?? $input.first().json;
const headers = $input.first().json.headers ?? {};

const ref = body.ref || '';
const branch = ref.startsWith('refs/heads/') ? ref.replace('refs/heads/', '') : (body.branch || 'unknown');
const sha = (body.after || body.head_commit?.id || '').slice(0, 12) || 'latest';
const repo = body.repository?.full_name || body.repository?.name || 'unknown';
const pusher = body.pusher?.name || body.sender?.login || 'unknown';
const compare = body.compare || '';
const commits = Array.isArray(body.commits) ? body.commits.length : 0;
const isMain = branch === 'main' || branch === 'master';

return [{
  json: {
    ref,
    branch,
    sha,
    repo,
    pusher,
    compare,
    commits,
    isMain,
    delivery: headers['x-github-delivery'] || headers['X-GitHub-Delivery'] || '',
    event: headers['x-github-event'] || headers['X-GitHub-Event'] || 'push',
  }
}];

const parse = $('Parse GitHub Payload').first().json;
const ssh = $input.first().json;
const stdout = ssh.stdout || ssh.data || JSON.stringify(ssh);
const stderr = ssh.stderr || '';
const code = ssh.code ?? ssh.exitCode ?? 0;
const ok = !stderr || String(code) === '0' || String(stdout).includes('Deployed');

// Heuristic: SSH node often puts command output in stdout
const success = String(stdout).includes('Deployed') || (String(code) === '0' && !String(stdout).toLowerCase().includes('error'));

return [{
  json: {
    success,
    branch: parse.branch,
    sha: parse.sha,
    repo: parse.repo,
    pusher: parse.pusher,
    image: `smitambalia/n8n:${parse.sha}`,
    stdout: String(stdout).slice(-4000),
    stderr: String(stderr).slice(-2000),
    summary: success
      ? `✅ CI OK: ${parse.repo}@${parse.sha} → k3s`
      : `❌ CI FAILED: ${parse.repo}@${parse.sha}`,
  }
}];
